          <!-- Dynamic file items injected here -->
        </div>
      </div>
    </div>

    <!-- ========================================== -->
    <!-- NOTEPAD WINDOW                             -->
    <!-- ========================================== -->
    <div id="notepad-window" class="window" style="top: 150px; left: 250px;">
      <div class="window-header">
        <span class="window-title">Text Editor</span>
        <div class="window-controls">
          <button class="win-btn win-close" title="Close">×</button>
        </div>
      </div>
      <div class="window-content">
