        </div>
        <textarea id="editor" placeholder="Start typing here..." spellcheck="false"></textarea>
      </div>
    </div>

  </div>

  <script>
    /* ========================================== */
    /* SYSTEM & WINDOW MANAGEMENT                 */
    /* ========================================== */
    const desktop = document.getElementById('desktop');
    const windows = document.querySelectorAll('.window');
    const openFilesBtn = document.getElementById('open-files');
    const openNotepadBtn = document.getElementById('open-notepad');
    const filesWindow = document.getElementById('files-window');
    const notepadWindow = document.getElementById('notepad-window');

    // Live Clock
    function updateClock() {
      const clockEl = document.getElementById('live-clock');
      const now = new Date();
      const options = { month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' };
      clockEl.textContent = now.toLocaleDateString('en-US', options);
    }
    setInterval(updateClock, 1000);
    updateClock();

    // Bring Window to Front
    function makeActive(win) {
      windows.forEach(w => w.classList.remove('active'));
      win.classList.add('active');
    }

    // Window Dragging Functionality
    windows.forEach(win => {
      const header = win.querySelector('.window-header');
      let isDragging = false;
      let startX, startY, initialLeft, initialTop;

      header.addEventListener('mousedown', (e) => {
        if (e.target.classList.contains('win-btn')) return;
        isDragging = true;
        makeActive(win);

        startX = e.clientX;
        startY = e.clientY;

        const rect = win.getBoundingClientRect();
        initialLeft = rect.left;
        initialTop = rect.top;

        document.addEventListener('mousemove', drag);
        document.addEventListener('mouseup', stopDrag);
      });

      function drag(e) {
        if (!isDragging) return;
        const dx = e.clientX - startX;
        const dy = e.clientY - startY;

        let newLeft = initialLeft + dx;
        let newTop = initialTop + dy;

        // Keep header somewhat visible on screen
        if (newTop < 28) newTop = 28; // below top bar
        if (newTop > window.innerHeight - 40) newTop = window.innerHeight - 40;
        if (newLeft < -win.offsetWidth + 100) newLeft = -win.offsetWidth + 100;
        if (newLeft > window.innerWidth - 100) newLeft = window.innerWidth - 100;

        win.style.left = `${newLeft}px`;
        win.style.top = `${newTop}px`;
      }

      function stopDrag() {
        isDragging = false;
        document.removeEventListener('mousemove', drag);
        document.removeEventListener('mouseup', stopDrag);
      }

      // Click window body to focus
      win.addEventListener('mousedown', () => makeActive(win));

      // Close button handler
      const closeBtn = win.querySelector('.win-close');
      closeBtn.addEventListener('click', () => {
        win.style.display = 'none';
        // Update dock indicators
        if (win === filesWindow) openFilesBtn.classList.remove('running');
        if (win === notepadWindow) openNotepadBtn.classList.remove('running');
      });
    });

    // Launcher Actions
    openFilesBtn.addEventListener('click', () => {
      filesWindow.style.display = 'flex';
      openFilesBtn.classList.add('running');
      makeActive(filesWindow);
    });

    openNotepadBtn.addEventListener('click', () => {
      notepadWindow.style.display = 'flex';
      openNotepadBtn.classList.add('running');
      makeActive(notepadWindow);
    });


    /* ========================================== */
    /* FILES APP (VIRTUAL FILESYSTEM)             */
    /* ========================================== */
    const fsData = {
      '/': {
        type: 'dir',
        children: {
          'bin': { type: 'dir', children: {} },
          'etc': { type: 'dir', children: {} },
          'home': {
            type: 'dir',
            children: {
              'user': {
                type: 'dir',
                children: {
                  'Documents': {
                    type: 'dir',
                    children: {
                      'notes.txt': { type: 'file', content: 'Welcome to Ubuntu! This is a text file.' },
                      'todo.txt': { type: 'file', content: '1. Build a cool desktop\n2. Polish the UI\n3. Ship it!' }
                    }
                  },
                  'Downloads': { type: 'dir', children: {} },
                  'Pictures': { type: 'dir', children: {} }
                }
              }
            }
          },
          'usr': { type: 'dir', children: {} },
          'var': { type: 'dir', children: {} }
        }
      }
    };

    let currentPath = '/';
    const filesPathEl = document.getElementById('files-path');
    const filesListEl = document.getElementById('files-list');
    const filesUpBtn = document.getElementById('files-up');

    // Helper to resolve path to node
    function getNodeByPath(path) {
      if (path === '/') return fsData['/'];
      const parts = path.split('/').filter(Boolean);
      let current = fsData['/'];
      for (const part of parts) {
        if (current && current.children && current.children[part]) {
          current = current.children[part];
        } else {
          return null;
        }
      }
      return current;
    }

    function renderFiles() {
      filesPathEl.textContent = currentPath;
      filesListEl.innerHTML = '';

      // Enable/disable Up button
      filesUpBtn.disabled = (currentPath === '/');

      const node = getNodeByPath(currentPath);
      if (!node || node.type !== 'dir') return;

      const items = node.children;
      Object.keys(items).forEach(name => {
        const item = items[name];
        const itemEl = document.createElement('div');
        itemEl.className = 'fs-item';

        // Icon based on type
        let iconSvg = '';
        if (item.type === 'dir') {
          iconSvg = `<svg class="svg-folder" viewBox="0 0 24 24" width="48" height="48"><path d="M10 4H4c-1.1 0-1.99.9-1.99 2L2 18c0 1.1.9 2 2 2h16c1.1 0 2-.9 2-2V8c0-1.1-.9-2-2-2h-8l-2-2z"/></svg>`;
        } else {
          iconSvg = `<svg class="svg-file" viewBox="0 0 24 24" width="48" height="48"><path d="M14 2H6c-1.1 0-1.99.9-1.99 2L4 20c0 1.1.89 2 1.99 2H18c1.1 0 2-.9 2-2V8l-6-6zm2 16H8v-2h8v2zm0-4H8v-2h8v2zm-3-5V3.5L18.5 9H13z"/></svg>`;
        }

        itemEl.innerHTML = `
          <div class="fs-icon">${iconSvg}</div>
          <div class="fs-name">${name}</div>
        `;

        // Single click to select
        itemEl.addEventListener('click', (e) => {
          e.stopPropagation();
          document.querySelectorAll('.fs-item').forEach(el => el.classList.remove('selected'));
          itemEl.classList.add('selected');
        });

        // Double click to open/navigate
        itemEl.addEventListener('dblclick', () => {
          if (item.type === 'dir') {
            currentPath = currentPath === '/' ? `/${name}` : `${currentPath}/${name}`;
            renderFiles();
          } else {
            // Open text files in Notepad
            openFileInNotepad(name, item.content || '');
          }
        });

        filesListEl.appendChild(itemEl);
      });
    }

    // Go Up directory
    filesUpBtn.addEventListener('click', () => {
      if (currentPath === '/') return;
      const parts = currentPath.split('/').filter(Boolean);
      parts.pop();
      currentPath = '/' + parts.join('/');
      renderFiles();
    });

    // Deselect items when clicking empty space
    filesListEl.addEventListener('click', () => {
      document.querySelectorAll('.fs-item').forEach(el => el.classList.remove('selected'));
    });

    // Initialize Files
    renderFiles();


    /* ========================================== */
    /* NOTEPAD APP (TABBED & PERSISTENT)          */
    /* ========================================== */
    const tabsContainer = document.getElementById('tabs');
    const newTabBtn = document.getElementById('new-tab');
    const editor = document.getElementById('editor');

    let notepadData = {
      tabs: [],
      activeTabId: null
    };

    // Load from LocalStorage
    function loadNotepadState() {
      const saved = localStorage.getItem('ubuntu_notepad_state');
      if (saved) {
        try {
          notepadData = JSON.parse(saved);
        } catch (e) {
          console.error("Failed to parse saved notepad state", e);
        }
      }

      // Fallback if empty
      if (!notepadData.tabs || notepadData.tabs.length === 0) {
        notepadData.tabs = [
          { id: 'tab-1', title: 'Document 1', content: 'Welcome to the Text Editor!\n\nAll tabs and content are saved automatically to localStorage.' }
        ];
        notepadData.activeTabId = 'tab-1';
      }

      renderTabs();
    }

    // Save to LocalStorage
    function saveNotepadState() {
      localStorage.setItem('ubuntu_notepad_state', JSON.stringify(notepadData));
    }

    function renderTabs() {
      tabsContainer.innerHTML = '';

      notepadData.tabs.forEach(tab => {
        const tabEl = document.createElement('div');
        tabEl.className = `tab ${tab.id === notepadData.activeTabId ? 'active' : ''}`;
        tabEl.dataset.id = tab.id;

        tabEl.innerHTML = `
          <span class="tab-title">${tab.title}</span>
          <span class="tab-close" title="Close Tab">×</span>
        `;

        // Switch to tab
        tabEl.addEventListener('click', (e) => {
          if (e.target.classList.contains('tab-close')) return;
          switchTab(tab.id);
        });

        // Close tab
        tabEl.querySelector('.tab-close').addEventListener('click', (e) => {
          e.stopPropagation();
          closeTab(tab.id);
        });

        tabsContainer.appendChild(tabEl);
      });

      // Update editor content
      const activeTab = notepadData.tabs.find(t => t.id === notepadData.activeTabId);
      if (activeTab) {
        editor.value = activeTab.content;
        editor.disabled = false;
      } else {
        editor.value = '';
        editor.disabled = true;
      }
    }

    function switchTab(id) {
      notepadData.activeTabId = id;
      saveNotepadState();
      renderTabs();
    }

    function closeTab(id) {
      const index = notepadData.tabs.findIndex(t => t.id === id);
      if (index === -1) return;

      notepadData.tabs.splice(index, 1);

      if (notepadData.activeTabId === id) {
        if (notepadData.tabs.length > 0) {
          // Switch to adjacent tab
          const nextActiveIndex = Math.min(index, notepadData.tabs.length - 1);
          notepadData.activeTabId = notepadData.tabs[nextActiveIndex].id;
        } else {
          notepadData.activeTabId = null;
        }
      }

      saveNotepadState();
      renderTabs();
    }

    // Create New Tab
    newTabBtn.addEventListener('click', () => {
      const newId = 'tab-' + Date.now();
      const newNum = notepadData.tabs.length + 1;
      const newTab = {
        id: newId,
        title: `Document ${newNum}`,
        content: ''
      };
      notepadData.tabs.push(newTab);
      notepadData.activeTabId = newId;
      saveNotepadState();
      renderTabs();
      editor.focus();
    });

    // Handle Editor Input
    editor.addEventListener('input', () => {
      const activeTab = notepadData.tabs.find(t => t.id === notepadData.activeTabId);
      if (activeTab) {
        activeTab.content = editor.value;
        saveNotepadState();
      }
    });

    // Open File from Files App into Notepad
    function openFileInNotepad(filename, content) {
      // Check if already open
      let existingTab = notepadData.tabs.find(t => t.title === filename);
      if (existingTab) {
        notepadData.activeTabId = existingTab.id;
      } else {
        const newId = 'tab-' + Date.now();
        notepadData.tabs.push({
          id: newId,
          title: filename,
          content: content
        });
        notepadData.activeTabId = newId;
      }

      saveNotepadState();
